import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate a car loan payment?", a: "Subtract down payment and trade-in from the taxed vehicle price, then use the loan amortization formula with monthly interest rate and loan term." },
  { q: "How much should you put down on a car?", a: "A common guideline is 20% down for a new car and at least 10% for a used car to reduce interest and avoid negative equity." },
  { q: "What is a good interest rate for an auto loan?", a: "A good auto loan rate depends on credit, vehicle, and market rates. Excellent credit usually qualifies for the lowest rates." },
  { q: "Should you finance a car for 60 or 72 months?", a: "A 60-month loan usually costs less interest. A 72-month loan lowers monthly payments but increases total cost." },
  { q: "How does a trade-in affect your car loan?", a: "A trade-in reduces the amount you need to finance, which lowers monthly payment and total interest." },
];

const money = (n: number) => formatCurrencyValue(n, { maximumFractionDigits: 2 });
const money0 = (n: number) => formatCurrencyValue(n, { maximumFractionDigits: 0 });
const pay = (p: number, rate: number, months: number) => {
  const r = rate / 100 / 12;
  return r ? p * r * Math.pow(1 + r, months) / (Math.pow(1 + r, months) - 1) : p / months;
};

export default function AutoLoanCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(30000);
  const [down, setDown] = useState(5000);
  const [trade, setTrade] = useState(2000);
  const [tax, setTax] = useState(6);
  const [rate, setRate] = useState(6);
  const [months, setMonths] = useState(60);
  const taxedPrice = price * (1 + tax / 100);
  const principal = Math.max(0, taxedPrice - down - trade);
  const monthly = pay(principal, rate, months);
  const totalInterest = monthly * months - principal;
  const totalCost = monthly * months + down + trade;
  const schedule = useMemo(() => {
    const rows: Array<{ month: number; payment: number; principal: number; interest: number; balance: number }> = [];
    let balance = principal; const r = rate / 100 / 12;
    for (let month = 1; month <= months; month++) { const interest = balance * r; const principalPaid = Math.min(monthly - interest, balance); balance = Math.max(0, balance - principalPaid); rows.push({ month, payment: monthly, principal: principalPaid, interest, balance }); }
    return rows;
  }, [principal, rate, months, monthly]);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  const rows = [10000, 20000, 30000, 40000, 50000].map((p) => ({ p, r3: pay(p, 3, 60), r5: pay(p, 5, 60), r7: pay(p, 7, 60), int5: pay(p, 5, 60) * 60 - p }));

  return (
    <>
      <SEOHead title="Free Auto Loan Calculator Online - Calculate Car Loan Payments Instantly | CalcHive" description="Free online auto loan calculator. Calculate monthly car loan payments, total interest and full amortization for any vehicle price, rate and term instantly. 100% free, no signup required." canonical="/auto-loan-calculator" keywords="free auto loan calculator, car loan calculator free online, monthly car payment calculator free, calculate auto loan free, vehicle loan calculator free online" category="Financial Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Auto Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate monthly car loan payment, total loan amount, total interest, total cost, and amortization instantly.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">{[["Vehicle price", price, setPrice], ["Down payment", down, setDown], ["Trade-in value", trade, setTrade], ["Sales tax (%)", tax, setTax], ["Interest rate (%)", rate, setRate], ["Loan term (months)", months, setMonths]].map(([label, val, setter]) => <div key={label as string}><label className="text-sm font-semibold text-foreground block mb-2">{label as string}</label><input type="number" value={val as number} onChange={(e) => (setter as (n:number)=>void)(Number(e.target.value))} className={inputClass} /></div>)}</div>
          <motion.div key={`${price}-${down}-${trade}-${tax}-${rate}-${months}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-6xl font-black text-white" data-testid="result-monthly">{money(monthly)}</p></div><div className="grid grid-cols-3 gap-3 mt-4">{[["Loan Amount", principal], ["Total Interest", totalInterest], ["Total Cost", totalCost]].map(([l,v]) => <div key={l as string} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground">{l as string}</p><p className="font-extrabold text-foreground">{money(v as number)}</p></div>)}</div></motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Your Car Loan Monthly Payment for Free</h2><p className="text-muted-foreground leading-relaxed">The calculator adds sales tax, subtracts down payment and trade-in, then amortizes the financed balance over the selected term.</p><h2 className="text-2xl font-bold text-foreground">How Down Payment and Trade-In Affect Your Auto Loan</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Monthly Payment on Car Loans by Price and Rate</caption><thead className="bg-muted/60"><tr>{["Car Price","3% Rate 60mo","5% Rate 60mo","7% Rate 60mo","Total Interest at 5%"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map(r => <tr key={r.p}><td className="py-2.5 px-3 font-semibold">{money0(r.p)}</td><td className="py-2.5 px-3">{money(r.r3)}</td><td className="py-2.5 px-3">{money(r.r5)}</td><td className="py-2.5 px-3">{money(r.r7)}</td><td className="py-2.5 px-3">{money(r.int5)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Car Loan Payment Calculator for Everyone</h2><div className="overflow-x-auto max-h-96"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Amortization Schedule</caption><thead className="bg-muted/60 sticky top-0"><tr>{["Month","Payment","Principal","Interest","Balance"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{schedule.map(r => <tr key={r.month}><td className="py-2 px-3">{r.month}</td><td className="py-2 px-3">{money(r.payment)}</td><td className="py-2 px-3">{money(r.principal)}</td><td className="py-2 px-3">{money(r.interest)}</td><td className="py-2 px-3">{money(r.balance)}</td></tr>)}</tbody></table></div></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/auto-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


